gnal.name,\n44\t    detail: signal.detail\n45\t  }));\n46\t\n47\t  // Owner availability: every routed owner group gets a task, in order, with a\n48\t  // due date derived from the contract response window relative to `now`.\n49\t  const escalatedAt = new Date(now);\n50\t  const responseHours = resolveResponseHours(account);\n51\t\n52\t  db.workflow_state.push({\n53\t    _id: `state-${requestId}`,\n54\t    requestId,\n55\t    accountId: request.accountId,\n56\t    title: request.title,\n57\t    status: ESCALATED_STATUS,\n58\t    tier: account?.tier ?? null,\n59\t    supportPlan: account?.contract?.supportPlan ?? null,\n60\t    riskSignals,\n61\t    nextStep: request.nextStep,\n62\t    ownerGroups: request.ownerGroups.slice(),\n63\t    openIncidentCount: openIncidents.length,\n64\t    escalatedAt: escalatedAt.toISOString(),\n65\t    updatedAt: escalatedAt.toISOString()\n66\t  });\n67\t\n68\t  request.ownerGroups.forEach((ownerGroup, index) => {\n69\t    // Front-line owner responds within the SLA window; downstream groups are\n70\t    // staggered by one window each so the response timeline is auditable.\n71\t    const dueAt = new Date(\n72\t      escalatedAt.getTime() + responseHours * (index + 1) * 60 * 60 * 1000\n73\t    );\n74\t    db.owner_tasks.push({\n75\t      _id: `task-${requestId}-${slugify(ownerGroup)}`,\n76\t      requestId,\n77\t      ownerGroup,\n78\t      title: `${ownerGroup} response for ${request.title}`,\n79\t      status: \"open\",\n80\t      dueAt: dueAt.toISOString(),\n81\t      responseWindowHours: responseHours,\n82\t      createdAt: escalatedAt.toISOString()\n83\t    });\n84\t  });\n85\t\n86\t  const ownerList = request.ownerGroups.join(\", \");\n87\t  const customerBody =\n88\t    request.customerMessage ||\n89\t    `Your case \"${request.title}\" has been escalated and is being handled by ${ownerList}.`;\n90\t\n91\t  db.customer_messages.push({\n92\t    _id: `msg-${requestId}`,\n93\t    requestId,\n94\t    audience: \"customer\",\n95\t    body: customerBody,\n96\t    sentAt: escalatedAt.toISOString()\n97\t  });\n98\t\n99\t  // Timer audit: records escalation time, the response window, and the breach\n100\t  // state. Customer-visible because the account requires a customer-visible\n101\t  // audit trail (see account.context.complianceFlags).\n102\t  const breachDeadline = new Date(\n103\t    escalatedAt.getTime() + responseHours * 60 * 60 * 1000\n104\t  );\n105\t  db.audit_events.push({\n106\t    _id: `audit-${requestId}`,\n107\t    requestId,\n108\t    type: \"sla-breach-escalation\",\n109\t    customerVisible: true,\n110\t    escalatedAt: escalatedAt.toISOString(),\n111\t    responseWindowHours: responseHours,\pace/3f601996-8bd7-4ee8-8366-486834d75ed1/tasks/a14e2718bd46262fa.output","summary":"Agent \"Dump contract files verbatim\" came to rest","usage":{"total_tokens":22258,"tool_uses":2,"duration_ms":29834},"session_id":"3f601996-8bd7-4ee8-8366-486834d75ed1","uuid":"c8a12114-9140-4410-bbc6-eddc6f1122ec"}
